print('__RESULT__:')
print(json.dumps({
    'total_nyse_stocks': len(all_nyse_symbols),
    'sample_symbols': all_nyse_symbols[:10],
    'sample_names': [symbol_to_name[sym] for sym in all_nyse_symbols[:5]]
}))"}
